class Solution {
public:
    string reverseParentheses(string s) {
        stack<string> st;
        string temp = "";
        for (char c : s) {
            if (c == '(') {
                st.push(temp);
                temp = "";
            } else if (c == ')') {
                string rev = temp;
                reverse(rev.begin(), rev.end());
                temp = st.top() + rev;
                st.pop();
            } else {
                temp += c;
            }
        }
        return temp;
    }
};
